function bisectLeft(a, x) {
    let lo = 0, hi = a.length;
    while (lo < hi) { const m = (lo + hi) >> 1; if (a[m] < x) lo = m + 1; else hi = m; }
    return lo;
}
function bisectRight(a, x) {
    let lo = 0, hi = a.length;
    while (lo < hi) { const m = (lo + hi) >> 1; if (a[m] <= x) lo = m + 1; else hi = m; }
    return lo;
}
class RangeModule {
    constructor() {
        this.bounds = [];
    }
    addRange(left, right) {
        const b = this.bounds;
        const i = bisectLeft(b, left);
        const j = bisectRight(b, right);
        const mid = [];
        if (i % 2 === 0) mid.push(left);
        if (j % 2 === 0) mid.push(right);
        this.bounds = b.slice(0, i).concat(mid, b.slice(j));
    }
    queryRange(left, right) {
        const b = this.bounds;
        const i = bisectRight(b, left);
        const j = bisectLeft(b, right);
        return i === j && i % 2 === 1;
    }
    removeRange(left, right) {
        const b = this.bounds;
        const i = bisectLeft(b, left);
        const j = bisectRight(b, right);
        const mid = [];
        if (i % 2 === 1) mid.push(left);
        if (j % 2 === 1) mid.push(right);
        this.bounds = b.slice(0, i).concat(mid, b.slice(j));
    }
}
